#!/usr/bin/env node
// Scans public/companion-pack/<app>/<kind>.pdf and writes a deterministic JSON
// manifest at src/data/companion-pack-manifest.json. The per-app page imports
// the JSON directly (no node:fs needed at SSG runtime), so this works in both
// Node-static and Cloudflare Pages hybrid-SSR builds.
//
// Mirrors scripts/build-cast-manifest.mjs.
//
// Output shape:
//   {
//     "appslug": ["coloring", "puzzle_sampler", "cast_poster", "parent_letter"],
//     ...
//   }
//
// Run before `astro build` (wired in package.json prebuild hook).
// Source PDFs are generated by labsmith/scripts/build_companion_pack.py.

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const ROOT = path.resolve(__dirname, '..');
const PACK_DIR = path.join(ROOT, 'public', 'companion-pack');
const OUT = path.join(ROOT, 'src', 'data', 'companion-pack-manifest.json');

const KNOWN_KINDS = ['coloring', 'puzzle_sampler', 'cast_poster', 'parent_letter'];

const manifest = {};
let totalPdfs = 0;
if (fs.existsSync(PACK_DIR)) {
  for (const appDir of fs.readdirSync(PACK_DIR).sort()) {
    const appPath = path.join(PACK_DIR, appDir);
    if (!fs.statSync(appPath).isDirectory()) continue;
    const kinds = [];
    for (const file of fs.readdirSync(appPath).sort()) {
      if (!file.endsWith('.pdf')) continue;
      const kind = file.replace(/\.pdf$/, '');
      if (KNOWN_KINDS.includes(kind)) {
        kinds.push(kind);
        totalPdfs += 1;
      }
    }
    if (kinds.length > 0) {
      // Preserve canonical order (coloring → puzzle_sampler → cast_poster → parent_letter)
      manifest[appDir] = KNOWN_KINDS.filter(k => kinds.includes(k));
    }
  }
}

fs.writeFileSync(OUT, JSON.stringify(manifest, null, 2) + '\n');
const appCount = Object.keys(manifest).length;
console.log(`companion-pack-manifest: ${totalPdfs} PDFs across ${appCount} apps`);
